#!/bin/sh
#
# ** Do not edit **
# This script is generated by cheri-benchplot.
#

set -e

echo "Run benchmark configuration ID=3774e0bd-2452-4b33-8d2c-39b6f0ce4620 with 2 iterations."
echo "Instance 'hybrid-kernel'"
echo "Parameters:"
echo -e "\thost='morello-hybrid'"
echo -e "\tbufsize='1M'"
echo -e "\ttarget='hybrid-kernel'"

#### Global setup
echo "Global benchmark setup"
sysctl security.cheri.runtime_revocation_default=0
sysctl security.cheri.lib_based_c18n_default=0
[ -z "$(ifconfig lo2)" ] && ifconfig lo2 create
ifconfig lo2 mtu 1500 up
ifconfig lo2 10.0.0.1 netmask 255.255.255.0

# Ensure that we have no stray iperf data from previous runs
find . -regex './[0-9]+/.*\.json' -delete

#### Run loop
echo "Run benchmark for 2 iterations"
for ITERATION in $(seq 0 1); do

    # Per-iteration iperf setup
    # Start localhost iperf server
    # We use a --one-off server to ensure that any process state is entirely reset
    iperf3 -s --one-off --daemon --pidfile /tmp/iperf_server.pid \
        --bind 10.0.0.1 \
        -A 0 -4
    # Make sure we have time to get the server up
    sleep 1

    iperf3 \
        -c 10.0.0.1 \
        -P 1 \
        --interval 0 \
        -n 1G \
        -l 1M \
        -A 1 -4 \
        -J --logfile ${ITERATION}/stats-iperf-exec-3774e0bd-2452-4b33-8d2c-39b6f0ce4620.json
done
echo "Benchmark done"

#### Global teardown
echo "Global benchmark teardown"

#### Global post-processing phase, per-iteration
echo "Post process hooks"
for ITERATION in $(seq 0 1); do
    :
done

#### Mark benchmark completed
date > ".run_completed"
